INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (0, "", "vo_asb", 72, 0, "", "vo_asb_0723", "", 72020, 21, "");
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (1, 1, 1, 72, 10, 0, "だからわたし、\n勇気を出して言ってみたんです！\nお友だちになりませんか、って。", 0, 72021, 11, 0);
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (0, "", 0, 72, 0, "", "", "", 72022, 91, "");
