INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (0, "", "vo_asb", 72, 0, "", "vo_asb_0726", "", 72032, 21, "");
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (1, 1, 1, 72, 10, 0, "そりゃそうですよね……\nいきなり前のめり過ぎ太郎でした……", 0, 72033, 11, 0);
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (0, "", 0, 72, 0, "", "", "", 72034, 91, "");
