INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (1, 1, 1, 142, 10, 0, "……でも。\n今回の冒険で、夢見ることは\n大きな力だと知りましたから。", 0, 142024, 11, 0);
